// User Roles
export type UserRole = 'applicant' | 'reviewer' | 'approver' | 'admin';

// Application States - State Machine
export type ApplicationStatus = 
  | 'draft'
  | 'submitted'
  | 'under_review'
  | 'additional_info_required'
  | 'reviewed'
  | 'approved'
  | 'rejected';

// Valid state transitions
export const VALID_TRANSITIONS: Record<ApplicationStatus, ApplicationStatus[]> = {
  draft: ['submitted'],
  submitted: ['under_review'],
  under_review: ['additional_info_required', 'reviewed'],
  additional_info_required: ['submitted'],
  reviewed: ['approved', 'rejected'],
  approved: [], // Terminal state
  rejected: [], // Terminal state
};

// Action types for audit log
export type AuditAction = 
  | 'application_created'
  | 'application_submitted'
  | 'application_assigned'
  | 'review_started'
  | 'additional_info_requested'
  | 'additional_info_submitted'
  | 'review_completed'
  | 'application_approved'
  | 'application_rejected'
  | 'document_uploaded'
  | 'document_version_added'
  | 'user_created'
  | 'user_updated'
  | 'user_login'
  | 'user_logout';

// User interface
export interface User {
  id: string;
  email: string;
  passwordHash: string;
  name: string;
  role: UserRole;
  createdAt: string;
  updatedAt: string;
  isActive: boolean;
}

// User without sensitive data
export interface SafeUser {
  id: string;
  email: string;
  name: string;
  role: UserRole;
  createdAt: string;
  updatedAt: string;
  isActive: boolean;
}

// Application interface
export interface Application {
  id: string;
  referenceNumber: string;
  applicantId: string;
  bankName: string;
  bankType: 'commercial' | 'microfinance' | 'development' | 'cooperative';
  businessAddress: string;
  contactEmail: string;
  contactPhone: string;
  proposedCapital: number;
  businessPlan: string;
  status: ApplicationStatus;
  reviewerId: string | null;
  approverId: string | null;
  reviewNotes: string | null;
  reviewRecommendation: 'approve' | 'reject' | null;
  approvalNotes: string | null;
  rejectionReason: string | null;
  additionalInfoRequest: string | null;
  createdAt: string;
  updatedAt: string;
  submittedAt: string | null;
  reviewedAt: string | null;
  decidedAt: string | null;
  version: number; // For optimistic locking / concurrent access handling
}

// Document interface with versioning
export interface Document {
  id: string;
  applicationId: string;
  name: string;
  type: string;
  size: number;
  uploadedBy: string;
  uploadedAt: string;
  version: number;
  previousVersionId: string | null;
  isLatest: boolean;
  // Simulated storage path (no actual cloud storage)
  storagePath: string;
}

// Audit Log Entry - Append-only, immutable
export interface AuditLogEntry {
  id: string;
  timestamp: string;
  userId: string;
  userEmail: string;
  userName: string;
  userRole: UserRole;
  action: AuditAction;
  entityType: 'application' | 'document' | 'user';
  entityId: string;
  stateBefore: string | null; // JSON stringified
  stateAfter: string | null; // JSON stringified
  metadata: string | null; // Additional context, JSON stringified
  ipAddress: string | null;
  userAgent: string | null;
}

