import { SignJWT, jwtVerify } from 'jose';
import { cookies } from 'next/headers';
import type { JWTPayload, SafeUser, UserRole, RolePermissions } from './types';
import { ROLE_PERMISSIONS } from './types';
import { db } from './db';

const JWT_SECRET = new TextEncoder().encode(
  process.env.JWT_SECRET || 'your-super-secret-key-change-in-production'
);

const TOKEN_EXPIRY = '8h';
const COOKIE_NAME = 'auth_token';

export async function createToken(user: SafeUser): Promise<string> {
  const token = await new SignJWT({
    userId: user.id,
    email: user.email,
    name: user.name,
    role: user.role,
  })
    .setProtectedHeader({ alg: 'HS256' })
    .setIssuedAt()
    .setExpirationTime(TOKEN_EXPIRY)
    .sign(JWT_SECRET);

  return token;
}

export async function verifyToken(token: string): Promise<JWTPayload | null> {
  try {
    const { payload } = await jwtVerify(token, JWT_SECRET);
    return payload as unknown as JWTPayload;
  } catch {
    return null;
  }
}

export async function setAuthCookie(token: string): Promise<void> {
  const cookieStore = await cookies();
  cookieStore.set(COOKIE_NAME, token, {
    httpOnly: true,
    secure: process.env.NODE_ENV === 'production',
    sameSite: 'lax',
    maxAge: 60 * 60 * 8, // 8 hours
    path: '/',
  });
}

export async function clearAuthCookie(): Promise<void> {
  const cookieStore = await cookies();
  cookieStore.delete(COOKIE_NAME);
}

export async function getAuthToken(): Promise<string | undefined> {
  const cookieStore = await cookies();
  return cookieStore.get(COOKIE_NAME)?.value;
}

export async function getCurrentUser(): Promise<SafeUser | null> {
  const token = await getAuthToken();
  if (!token) return null;

  const payload = await verifyToken(token);
  if (!payload) return null;

  const user = db.getUserById(payload.userId);
  if (!user || !user.isActive) return null;

  return {
    id: user.id,
    email: user.email,
    name: user.name,
    role: user.role,
    createdAt: user.createdAt,
    updatedAt: user.updatedAt,
    isActive: user.isActive,
  };
}

export function getPermissions(role: UserRole): RolePermissions {
  return ROLE_PERMISSIONS[role];
}

export function hasPermission(role: UserRole, permission: keyof RolePermissions): boolean {
  return ROLE_PERMISSIONS[role][permission];
}

// Check if user can perform maker-checker approval
// The reviewer cannot be the same as the approver
export function canApproveApplication(
  userId: string,
  applicationReviewerId: string | null
): boolean {
  // If the current user reviewed this application, they cannot approve it
  if (applicationReviewerId === userId) {
    return false;
  }
  return true;
}

export async function authenticateUser(
  email: string,
  password: string
): Promise<{ success: boolean; user?: SafeUser; token?: string; error?: string }> {
  const user = db.getUserByEmail(email);
  
  if (!user) {
    return { success: false, error: 'Invalid email or password' };
  }

  if (!user.isActive) {
    return { success: false, error: 'Account is deactivated' };
  }

  const isValidPassword = await db.verifyPassword(password, user.passwordHash);
  if (!isValidPassword) {
    return { success: false, error: 'Invalid email or password' };
  }

  const safeUser: SafeUser = {
    id: user.id,
    email: user.email,
    name: user.name,
    role: user.role,
    createdAt: user.createdAt,
    updatedAt: user.updatedAt,
    isActive: user.isActive,
  };

  const token = await createToken(safeUser);

  // Log the login action
  db.appendAuditLog({
    userId: user.id,
    userEmail: user.email,
    userName: user.name,
    userRole: user.role,
    action: 'user_login',
    entityType: 'user',
    entityId: user.id,
    stateBefore: null,
    stateAfter: null,
    metadata: JSON.stringify({ loginTime: new Date().toISOString() }),
    ipAddress: null,
    userAgent: null,
  });

  return { success: true, user: safeUser, token };
}
