import { v4 as uuidv4 } from 'uuid';
import bcrypt from 'bcryptjs';
import type { 
  User, 
  Application, 
  Document, 
  AuditLogEntry, 
  ApplicationStatus,
  AuditAction,
  UserRole,
  SafeUser
} from './types';
import { VALID_TRANSITIONS } from './types';

// In-memory database simulation
// In production, this would be a real database (PostgreSQL, etc.)

class Database {
  private users: Map<string, User> = new Map();
  private applications: Map<string, Application> = new Map();
  private documents: Map<string, Document> = new Map();
  private auditLog: AuditLogEntry[] = []; // Append-only array
  private applicationCounter: number = 0;

  constructor() {
    this.initializeSeedData();
  }

  private async initializeSeedData() {
    // Create seed users - one per role
    const seedUsers = [
      { email: 'applicant@test.com', name: 'John Applicant', role: 'applicant' as UserRole, password: 'password123' },
      { email: 'reviewer@bnr.rw', name: 'Jane Reviewer', role: 'reviewer' as UserRole, password: 'password123' },
      { email: 'approver@bnr.rw', name: 'Bob Approver', role: 'approver' as UserRole, password: 'password123' },
      { email: 'admin@bnr.rw', name: 'Alice Admin', role: 'admin' as UserRole, password: 'password123' },
      { email: 'reviewer2@bnr.rw', name: 'Mike Reviewer', role: 'reviewer' as UserRole, password: 'password123' },
      { email: 'approver2@bnr.rw', name: 'Sarah Approver', role: 'approver' as UserRole, password: 'password123' },
    ];

    for (const userData of seedUsers) {
      const passwordHash = await bcrypt.hash(userData.password, 10);
      const user: User = {
        id: uuidv4(),
        email: userData.email,
        passwordHash,
        name: userData.name,
        role: userData.role,
        createdAt: new Date().toISOString(),
        updatedAt: new Date().toISOString(),
        isActive: true,
      };
      this.users.set(user.id, user);
    }

    // Create seed applications in different states
    const applicant = Array.from(this.users.values()).find(u => u.role === 'applicant')!;
    const reviewer = Array.from(this.users.values()).find(u => u.role === 'reviewer')!;

    // Application 1: Under Review
    const app1: Application = {
      id: uuidv4(),
      referenceNumber: this.generateReferenceNumber(),
      applicantId: applicant.id,
      bankName: 'Rwanda Commercial Bank',
      bankType: 'commercial',
      businessAddress: '123 Kigali Business District, Kigali',
      contactEmail: 'info@rwandacommercial.rw',
      contactPhone: '+250 788 123 456',
      proposedCapital: 5000000000,
      businessPlan: 'We aim to provide innovative banking solutions to SMEs across Rwanda, focusing on digital-first approach and financial inclusion.',
      status: 'under_review',
      reviewerId: reviewer.id,
      approverId: null,
      reviewNotes: null,
      reviewRecommendation: null,
      approvalNotes: null,
      rejectionReason: null,
      additionalInfoRequest: null,
      createdAt: new Date(Date.now() - 7 * 24 * 60 * 60 * 1000).toISOString(),
      updatedAt: new Date().toISOString(),
      submittedAt: new Date(Date.now() - 5 * 24 * 60 * 60 * 1000).toISOString(),
      reviewedAt: null,
      decidedAt: null,
      version: 1,
    };
    this.applications.set(app1.id, app1);

    // Application 2: Submitted (waiting for review)
    const app2: Application = {
      id: uuidv4(),
      referenceNumber: this.generateReferenceNumber(),
      applicantId: applicant.id,
      bankName: 'Kigali Microfinance Institution',
      bankType: 'microfinance',
      businessAddress: '456 Nyarugenge District, Kigali',
      contactEmail: 'contact@kigalimfi.rw',
      contactPhone: '+250 788 234 567',
      proposedCapital: 500000000,
      businessPlan: 'Microfinance institution focused on rural communities and agricultural lending.',
      status: 'submitted',
      reviewerId: null,
      approverId: null,
      reviewNotes: null,
      reviewRecommendation: null,
      approvalNotes: null,
      rejectionReason: null,
      additionalInfoRequest: null,
      createdAt: new Date(Date.now() - 3 * 24 * 60 * 60 * 1000).toISOString(),
      updatedAt: new Date().toISOString(),
      submittedAt: new Date(Date.now() - 2 * 24 * 60 * 60 * 1000).toISOString(),
      reviewedAt: null,
      decidedAt: null,
      version: 1,
    };
    this.applications.set(app2.id, app2);

    // Add some sample documents
    const doc1: Document = {
      id: uuidv4(),
      applicationId: app1.id,
      name: 'Business_Plan_2024.pdf',
      type: 'application/pdf',
      size: 2500000,
      uploadedBy: applicant.id,
      uploadedAt: new Date(Date.now() - 6 * 24 * 60 * 60 * 1000).toISOString(),
      version: 1,
      previousVersionId: null,
      isLatest: true,
      storagePath: `/documents/${app1.id}/business_plan_v1.pdf`,
    };
    this.documents.set(doc1.id, doc1);

    const doc2: Document = {
      id: uuidv4(),
      applicationId: app1.id,
      name: 'Financial_Projections.xlsx',
      type: 'application/vnd.openxmlformats-officedocument.spreadsheetml.sheet',
      size: 1200000,
      uploadedBy: applicant.id,
      uploadedAt: new Date(Date.now() - 6 * 24 * 60 * 60 * 1000).toISOString(),
      version: 1,
      previousVersionId: null,
      isLatest: true,
      storagePath: `/documents/${app1.id}/financial_projections_v1.xlsx`,
    };
    this.documents.set(doc2.id, doc2);
  }

  private generateReferenceNumber(): string {
    this.applicationCounter++;
    const year = new Date().getFullYear();
    return `BNR-${year}-${String(this.applicationCounter).padStart(5, '0')}`;
  }

  // User operations
  async createUser(userData: Omit<User, 'id' | 'createdAt' | 'updatedAt' | 'passwordHash'> & { password: string }): Promise<SafeUser> {
    const passwordHash = await bcrypt.hash(userData.password, 10);
    const user: User = {
      id: uuidv4(),
      email: userData.email,
      passwordHash,
      name: userData.name,
      role: userData.role,
      createdAt: new Date().toISOString(),
      updatedAt: new Date().toISOString(),
      isActive: userData.isActive,
    };
    this.users.set(user.id, user);
    return this.toSafeUser(user);
  }

  getUserById(id: string): User | undefined {
    return this.users.get(id);
  }

  getUserByEmail(email: string): User | undefined {
    return Array.from(this.users.values()).find(u => u.email.toLowerCase() === email.toLowerCase());
  }

  getAllUsers(): SafeUser[] {
    return Array.from(this.users.values()).map(u => this.toSafeUser(u));
  }

  updateUser(id: string, updates: Partial<Omit<User, 'id' | 'createdAt' | 'passwordHash'>>): SafeUser | undefined {
    const user = this.users.get(id);
    if (!user) return undefined;
    
    const updatedUser: User = {
      ...user,
      ...updates,
      updatedAt: new Date().toISOString(),
    };
    this.users.set(id, updatedUser);
    return this.toSafeUser(updatedUser);
  }

  private toSafeUser(user: User): SafeUser {
    const { passwordHash, ...safeUser } = user;
    return safeUser;
  }

  // Application operations
  createApplication(data: Omit<Application, 'id' | 'referenceNumber' | 'createdAt' | 'updatedAt' | 'version'>): Application {
    const application: Application = {
      ...data,
      id: uuidv4(),
      referenceNumber: this.generateReferenceNumber(),
      createdAt: new Date().toISOString(),
      updatedAt: new Date().toISOString(),
      version: 1,
    };
    this.applications.set(application.id, application);
    return application;
  }

  getApplicationById(id: string): Application | undefined {
    return this.applications.get(id);
  }

  getApplicationsByApplicant(applicantId: string): Application[] {
    return Array.from(this.applications.values())
      .filter(a => a.applicantId === applicantId)
      .sort((a, b) => new Date(b.createdAt).getTime() - new Date(a.createdAt).getTime());
  }

  getAllApplications(): Application[] {
    return Array.from(this.applications.values())
      .sort((a, b) => new Date(b.createdAt).getTime() - new Date(a.createdAt).getTime());
  }

  getApplicationsByStatus(status: ApplicationStatus): Application[] {
    return Array.from(this.applications.values())
      .filter(a => a.status === status)
      .sort((a, b) => new Date(b.createdAt).getTime() - new Date(a.createdAt).getTime());
  }

  // Update application with optimistic locking
  updateApplication(
    id: string, 
    updates: Partial<Omit<Application, 'id' | 'referenceNumber' | 'createdAt' | 'applicantId'>>,
    expectedVersion: number
  ): { success: boolean; application?: Application; error?: string } {
    const application = this.applications.get(id);
    if (!application) {
      return { success: false, error: 'Application not found' };
    }

    // Optimistic locking check for concurrent access
    if (application.version !== expectedVersion) {
      return { 
        success: false, 
        error: 'Concurrent modification detected. Please refresh and try again.' 
      };
    }

    const updatedApplication: Application = {
      ...application,
      ...updates,
      updatedAt: new Date().toISOString(),
      version: application.version + 1,
    };
    this.applications.set(id, updatedApplication);
    return { success: true, application: updatedApplication };
  }

  // Validate state transition
  isValidTransition(currentStatus: ApplicationStatus, newStatus: ApplicationStatus): boolean {
    return VALID_TRANSITIONS[currentStatus].includes(newStatus);
  }

  // Document operations
  createDocument(data: Omit<Document, 'id' | 'uploadedAt'>): Document {
    // If this is a new version, mark previous as not latest
    if (data.previousVersionId) {
      const prevDoc = this.documents.get(data.previousVersionId);
      if (prevDoc) {
        this.documents.set(prevDoc.id, { ...prevDoc, isLatest: false });
      }
    }

    const document: Document = {
      ...data,
      id: uuidv4(),
      uploadedAt: new Date().toISOString(),
    };
    this.documents.set(document.id, document);
    return document;
  }

  getDocumentById(id: string): Document | undefined {
    return this.documents.get(id);
  }

  getDocumentsByApplication(applicationId: string, includeAllVersions = false): Document[] {
    return Array.from(this.documents.values())
      .filter(d => d.applicationId === applicationId && (includeAllVersions || d.isLatest))
      .sort((a, b) => new Date(b.uploadedAt).getTime() - new Date(a.uploadedAt).getTime());
  }

  getDocumentVersionHistory(documentId: string): Document[] {
    const doc = this.documents.get(documentId);
    if (!doc) return [];

    const versions: Document[] = [doc];
    let currentId = doc.previousVersionId;
    
    while (currentId) {
      const prevDoc = this.documents.get(currentId);
      if (prevDoc) {
        versions.push(prevDoc);
        currentId = prevDoc.previousVersionId;
      } else {
        break;
      }
    }
    
    return versions;
  }

  // Audit Log operations - APPEND ONLY
  appendAuditLog(entry: Omit<AuditLogEntry, 'id' | 'timestamp'>): AuditLogEntry {
    const auditEntry: AuditLogEntry = {
      ...entry,
      id: uuidv4(),
      timestamp: new Date().toISOString(),
    };
    
    // Append only - no modification or deletion allowed
    this.auditLog.push(auditEntry);
    return auditEntry;
  }

  // Read-only access to audit log
  getAuditLog(filters?: {
    entityType?: string;
    entityId?: string;
    userId?: string;
    action?: AuditAction;
    startDate?: string;
    endDate?: string;
  }): readonly AuditLogEntry[] {
    let results = [...this.auditLog];

    if (filters) {
      if (filters.entityType) {
        results = results.filter(e => e.entityType === filters.entityType);
      }
      if (filters.entityId) {
        results = results.filter(e => e.entityId === filters.entityId);
      }
      if (filters.userId) {
        results = results.filter(e => e.userId === filters.userId);
      }
      if (filters.action) {
        results = results.filter(e => e.action === filters.action);
      }
      if (filters.startDate) {
        results = results.filter(e => e.timestamp >= filters.startDate!);
      }
      if (filters.endDate) {
        results = results.filter(e => e.timestamp <= filters.endDate!);
      }
    }

    return results.sort((a, b) => new Date(b.timestamp).getTime() - new Date(a.timestamp).getTime());
  }

  getAuditLogForApplication(applicationId: string): readonly AuditLogEntry[] {
    return this.getAuditLog({ entityType: 'application', entityId: applicationId });
  }

  // Verify password
  async verifyPassword(plainPassword: string, hashedPassword: string): Promise<boolean> {
    return bcrypt.compare(plainPassword, hashedPassword);
  }
}

// Singleton instance
export const db = new Database();
